// upsertClient is the minimal client surface the upsert command needs. The
// real *client.Client satisfies it; tests inject a fake.
type upsertClient interface {
	Post(ctx context.Context, path string, body any) (json.RawMessage, int, error)
	Put(ctx context.Context, path string, body any) (json.RawMessage, int, error)
}

