// readUpsertRecords loads a JSON array of record objects from a file.
func readUpsertRecords(file string) ([]map[string]any, error) {
	data, err := os.ReadFile(file)
	if err != nil {
		return nil, fmt.Errorf("reading --file: %w", err)
	}
	var records []map[string]any
	if err := json.Unmarshal(data, &records); err != nil {
		return nil, fmt.Errorf("parsing --file JSON (want array of objects): %w", err)
	}
	return records, nil
}

// normalizePerson converts an input record into Copper's people shape. A
// scalar `email` is lifted into emails:[{email, category:"work"}]. An existing
// emails array is preserved as-is.
func normalizePerson(rec map[string]any) map[string]any {
	out := map[string]any{}
	for k, v := range rec {
		if k == "email" {
			continue
		}
		out[k] = v
	}
	if _, has := out["emails"]; !has {
		if email, ok := rec["email"].(string); ok && strings.TrimSpace(email) != "" {
			out["emails"] = []map[string]any{{"email": email, "category": "work"}}
		}
	}
	return out
}

// normalizeLead keeps the scalar `email` shape leads use.
func normalizeLead(rec map[string]any) map[string]any {
	out := map[string]any{}
	for k, v := range rec {
		out[k] = v
	}
	return out
}

// matchValue extracts the match key from a raw input record. For person+email
// it also looks inside an emails[] array.
func matchValue(entity, match string, rec map[string]any) string {
	if v, ok := rec[match].(string); ok && strings.TrimSpace(v) != "" {
		return strings.TrimSpace(v)
	}
	if entity == "person" && match == "email" {
		if arr, ok := rec["emails"].([]any); ok {
			for _, e := range arr {
				if m, ok := e.(map[string]any); ok {
					if em, ok := m["email"].(string); ok && strings.TrimSpace(em) != "" {
						return strings.TrimSpace(em)
					}
				}
			}
		}
	}
	return ""
}

// buildUpsertPlan normalizes each record and resolves the match value. The
// create-vs-update decision (which needs the network) is filled in later by
// runUpsert; here every item starts as "create" with its normalized body.
func buildUpsertPlan(entity, match string, records []map[string]any) ([]upsertPlanItem, error) {
	var plan []upsertPlanItem
	for i, rec := range records {
		mv := matchValue(entity, match, rec)
		if mv == "" {
			return nil, fmt.Errorf("record %d missing match field %q", i, match)
		}
		var body map[string]any
		if entity == "person" {
			body = normalizePerson(rec)
		} else {
			body = normalizeLead(rec)
		}
		plan = append(plan, upsertPlanItem{Match: mv, Action: "create", Body: body})
	}
	return plan, nil
}

// runUpsert executes the plan. Leads use Copper's server-side idempotent
// endpoint (PUT /leads/upsert matches by the configured key), so no client
// probe is needed. People have no single upsert endpoint, so we fetch by match
// value then PUT (update) or POST (create).
func runUpsert(ctx context.Context, c upsertClient, entity, match string, plan []upsertPlanItem) upsertSummary {
	summary := upsertSummary{Entity: entity, Failures: []string{}}
	for _, item := range plan {
		if entity == "lead" {
			// Server matches; reported as Updated because the endpoint is an
			// in-place upsert (existing rows are mutated, not duplicated).
			_, status, err := c.Put(ctx, "/leads/upsert", item.Body)
			if err != nil || status < 200 || status >= 300 {
				summary.Failures = append(summary.Failures, fmt.Sprintf("%s: status %d: %v", item.Match, status, err))
				continue
			}
			summary.Updated++
			continue
		}

		existingID, err := lookupExisting(ctx, c, entity, match, item.Match)
		if err != nil {
			summary.Failures = append(summary.Failures, fmt.Sprintf("%s: lookup: %v", item.Match, err))
			continue
		}
		var status int
		if existingID != "" {
			_, status, err = c.Put(ctx, upsertResourcePath(entity)+"/"+existingID, item.Body)
		} else {
			_, status, err = c.Post(ctx, upsertResourcePath(entity), item.Body)
		}
		if err != nil || status < 200 || status >= 300 {
			summary.Failures = append(summary.Failures, fmt.Sprintf("%s: status %d: %v", item.Match, status, err))
			continue
		}
		if existingID != "" {
			summary.Updated++
		} else {
			summary.Created++
		}
	}
	return summary
}

func upsertResourcePath(entity string) string {
	if entity == "lead" {
		return "/leads"
	}
	return "/people"
}

// lookupExisting finds an existing record id by the match value. For
// person+email it uses Copper's /people/fetch_by_email. Returns "" when none.
func lookupExisting(ctx context.Context, c upsertClient, entity, match, value string) (string, error) {
	if entity == "person" && match == "email" {
		data, status, err := c.Post(ctx, "/people/fetch_by_email", map[string]any{"email": value})
		if status == 404 {
			return "", nil
		}
		if err != nil {
			return "", err
		}
		var obj map[string]any
		if json.Unmarshal(data, &obj) == nil {
			if id, ok := obj["id"]; ok {
				return fmt.Sprintf("%v", normalizeID(id)), nil
			}
		}
		return "", nil
	}
	// Other entities/match keys: treat as create-only (no probe endpoint).
	return "", nil
}

func renderUpsertPlan(w io.Writer, entity string, plan []upsertPlanItem, summary upsertSummary, flags *rootFlags) error {
	if flags.asJSON || flags.agent {
		out := map[string]any{"entity": entity, "dry_run": true, "plan": plan}
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(out)
	}
	fmt.Fprintf(w, "PREVIEW: %d %s record(s) to upsert\n", len(plan), entity)
	for _, p := range plan {
		fmt.Fprintf(w, "  - match=%s -> %s\n", p.Match, p.Action)
	}
	fmt.Fprintln(w, "(re-run with --apply to execute)")
	return nil
}

func renderUpsertSummary(w io.Writer, summary upsertSummary, flags *rootFlags) error {
	if summary.Failures == nil {
		summary.Failures = []string{}
	}
	if flags.asJSON || flags.agent {
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(summary)
	}
	fmt.Fprintf(w, "%s: %d created, %d updated, %d skipped, %d failed\n",
		summary.Entity, summary.Created, summary.Updated, summary.Skipped, len(summary.Failures))
	for _, f := range summary.Failures {
		fmt.Fprintf(w, "  FAIL %s\n", f)
	}
	return nil
}
